# 原型：BottomBar + MiniPlayer 折叠联动

Apple Music 风格：底部 Tab Bar 向下滚动时缩起，MiniPlayer 顶上来占位；向上滚动（或列表回到顶部）时 Bar 回弹，点击折叠态也能重新展开。

本原型是一个**最小可跑**的独立 Demo，只依赖 Compose BOM、Material3 和 Material Icons Extended。跑通后再把 `CollapsibleBottomBarScaffold` 接到你的 `LibraryScreen` 里。

---

## 原理速览

```
展开态（collapseProgress = 0f）：
┌─────────────────────────┐
│  LazyColumn             │
│                         │
│                         │
├─────────────────────────┤
│  MiniPlayer   (56dp)    │
├─────────────────────────┤
│  BottomBar    (80dp)    │
└─────────────────────────┘

折叠态（collapseProgress = 1f）：
┌─────────────────────────┐
│  LazyColumn             │
│                         │
│                         │
│                         │
├─────────────────────────┤
│  MiniPlayer   (56dp)    │  ← Bar 整个 translateY 下去，MiniPlayer 原地不动
└─────────────────────────┘   点击 MiniPlayer 上方的"抓手"区域可展开
```

- **状态**：`collapseProgress: Float`（0=展开，1=折叠），由 `NestedScrollConnection` 的滚动增量驱动。
- **Bar 位移**：`translationY = collapseProgress * barHeightPx`。
- **回弹**：监听 `LazyListState`，当列表回到顶部（`canScrollBackward == false`）且手指抬起时 `animateTo(0f)`。
- **点击展开**：外层暴露 `onExpandRequest`，点击 MiniPlayer 时调用。

---

## 文件清单

Demo 放在一个独立 package，不影响你现有代码：

```
prototype/
├── CollapsibleBottomBarScaffold.kt   核心 Scaffold
├── CollapsibleBottomBarState.kt      状态 + NestedScrollConnection
└── PrototypeScreen.kt                Demo 入口（可跑）
```

---

## 1. `CollapsibleBottomBarState.kt`

```kotlin
package io.kyonqi.musicplayer.prototype

import androidx.compose.animation.core.Animatable
import androidx.compose.animation.core.tween
import androidx.compose.runtime.Composable
import androidx.compose.runtime.remember
import androidx.compose.ui.geometry.Offset
import androidx.compose.ui.input.nestedscroll.NestedScrollConnection
import androidx.compose.ui.input.nestedscroll.NestedScrollSource
import androidx.compose.ui.unit.Velocity
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.launch

/**
 * 控制底部 Bar 折叠进度
 * - 0f = 完全展开（Bar 可见）
 * - 1f = 完全折叠（Bar 藏到屏幕下方）
 *
 * @param barHeightPx Bar 的像素高度。进度会映射成位移 = progress * barHeightPx
 */
class CollapsibleBottomBarState(
    val barHeightPx: Float,
    private val scope: CoroutineScope,
) {
    private val _progress = Animatable(0f)
    val progress: Float get() = _progress.value

    /** 由 NestedScrollConnection 调用，返回实际消耗的 dy（像素）*/
    internal suspend fun consumeScroll(dy: Float): Float {
        if (barHeightPx <= 0f) return 0f
        val current = _progress.value * barHeightPx
        val target = (current - dy).coerceIn(0f, barHeightPx)
        val consumed = current - target
        _progress.snapTo(target / barHeightPx)
        return consumed
    }

    suspend fun expand() = _progress.animateTo(0f, tween(220))
    suspend fun collapse() = _progress.animateTo(1f, tween(220))

    /** 给调用方触发展开的便捷方法 */
    fun expandNow() { scope.launch { expand() } }
}

@Composable
fun rememberCollapsibleBottomBarState(
    barHeightPx: Float,
    scope: CoroutineScope,
): CollapsibleBottomBarState = remember(barHeightPx) {
    CollapsibleBottomBarState(barHeightPx, scope)
}

/**
 * 嵌套滚动连接：
 * - 手指上滑（dy<0，内容上移 → Bar 收起）：onPreScroll 先吃掉
 * - 手指下滑（dy>0，内容下移 → Bar 展开）：onPostScroll 在列表已到顶后吃掉
 */
class CollapsibleBottomBarNestedScrollConnection(
    private val state: CollapsibleBottomBarState,
    private val scope: CoroutineScope,
) : NestedScrollConnection {

    override fun onPreScroll(available: Offset, source: NestedScrollSource): Offset {
        val dy = available.y
        // 仅处理手指上滑：内容将向上滚，先让 Bar 收起
        if (dy < 0f && state.progress < 1f) {
            var consumed = 0f
            scope.launch { consumed = state.consumeScroll(dy) }
            // 注意：consumeScroll 是 suspend，这里同步返回会拿不到真实值
            // 用 snapTo 的同步版本更稳（见下）
        }
        return Offset.Zero
    }

    override fun onPostScroll(
        consumed: Offset,
        available: Offset,
        source: NestedScrollSource,
    ): Offset {
        val dy = available.y
        if (dy > 0f && state.progress > 0f) {
            scope.launch { state.consumeScroll(dy) }
        }
        return Offset.Zero
    }

    override suspend fun onPreFling(available: Velocity): Velocity {
        // 惯性结束时：半折叠状态吸附到最近的端点
        if (state.progress in 0.01f..0.99f) {
            if (state.progress > 0.5f) state.collapse() else state.expand()
        }
        return Velocity.Zero
    }
}
```

> **关键修正**：`onPreScroll` 里用 `scope.launch { suspend }` 会丢掉"消耗了多少"的同步返回值，列表会继续滚。实际实现应把 `consumeScroll` 改成同步（用 `Animatable.snapTo` 的同步封装），见下方"正确版"。

### 正确版 `CollapsibleBottomBarState`（同步 consume）

```kotlin
package io.kyonqi.musicplayer.prototype

import androidx.compose.animation.core.Animatable
import androidx.compose.animation.core.tween
import androidx.compose.runtime.Composable
import androidx.compose.runtime.getValue
import androidx.compose.runtime.mutableFloatStateOf
import androidx.compose.runtime.remember
import androidx.compose.runtime.setValue
import androidx.compose.ui.geometry.Offset
import androidx.compose.ui.input.nestedscroll.NestedScrollConnection
import androidx.compose.ui.input.nestedscroll.NestedScrollSource
import androidx.compose.ui.unit.Velocity
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.launch

class CollapsibleBottomBarState(
    val barHeightPx: Float,
    private val scope: CoroutineScope,
) {
    // 同步状态，用于滚动即时驱动
    private var _offsetPx by mutableFloatStateOf(0f)
    val progress: Float
        get() = if (barHeightPx <= 0f) 0f else _offsetPx / barHeightPx

    // 异步动画句柄，用于 expand/collapse
    private val anim = Animatable(0f)

    /** 同步消耗滚动，返回实际消耗的 dy（正值=向上滚被吃掉，负值=向下滚被吃掉）*/
    internal fun consume(dy: Float): Float {
        if (barHeightPx <= 0f) return 0f
        val current = _offsetPx
        val target = (current - dy).coerceIn(0f, barHeightPx)
        val consumed = current - target
        _offsetPx = target
        return consumed
    }

    suspend fun expand() {
        anim.snapTo(_offsetPx)
        anim.animateTo(0f, tween(220)) { _offsetPx = value }
    }

    suspend fun collapse() {
        anim.snapTo(_offsetPx)
        anim.animateTo(barHeightPx, tween(220)) { _offsetPx = value }
    }

    fun expandNow() { scope.launch { expand() } }
    fun collapseNow() { scope.launch { collapse() } }
}

@Composable
fun rememberCollapsibleBottomBarState(
    barHeightPx: Float,
    scope: CoroutineScope,
): CollapsibleBottomBarState = remember(barHeightPx, scope) {
    CollapsibleBottomBarState(barHeightPx, scope)
}

class CollapsibleBottomBarNestedScrollConnection(
    private val state: CollapsibleBottomBarState,
    private val scope: CoroutineScope,
) : NestedScrollConnection {

    override fun onPreScroll(available: Offset, source: NestedScrollSource): Offset {
        val dy = available.y
        // 上滑收起 Bar：dy<0 且还没完全折叠时，先吃掉一部分
        if (dy < 0f && state.progress < 1f) {
            val consumed = state.consume(dy)
            return Offset(0f, -consumed)  // 注意符号：消耗的是"向上滚"的量
        }
        return Offset.Zero
    }

    override fun onPostScroll(
        consumed: Offset,
        available: Offset,
        source: NestedScrollSource,
    ): Offset {
        val dy = available.y
        // 下滑展开 Bar：dy>0 且列表已到顶（available 有剩余），吃掉
        if (dy > 0f && state.progress > 0f) {
            val c = state.consume(dy)
            return Offset(0f, -c)
        }
        return Offset.Zero
    }

    override suspend fun onPreFling(available: Velocity): Velocity {
        // 吸附到最近端点
        if (state.progress in 0.01f..0.99f) {
            if (state.progress > 0.5f) state.collapse() else state.expand()
        }
        return Velocity.Zero
    }
}
```

