## 2. `CollapsibleBottomBarScaffold.kt`

```kotlin
package io.kyonqi.musicplayer.prototype

import androidx.compose.foundation.layout.Box
import androidx.compose.foundation.layout.PaddingValues
import androidx.compose.foundation.layout.padding
import androidx.compose.runtime.Composable
import androidx.compose.runtime.remember
import androidx.compose.runtime.rememberCoroutineScope
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.graphicsLayer
import androidx.compose.ui.input.nestedscroll.nestedScroll
import androidx.compose.ui.layout.Layout
import androidx.compose.ui.platform.LocalDensity
import androidx.compose.ui.unit.dp

/**
 * 折叠 Bar + MiniPlayer 的 Scaffold
 *
 * @param bottomBar         底部 Tab Bar（会随 progress 折叠）
 * @param miniPlayer        MiniPlayer（始终可见；点击它会触发 onMiniPlayerClick）
 * @param onMiniPlayerClick 点击 MiniPlayer 的回调（折叠态下用于展开 Bar，或打开 NowPlaying）
 * @param content           主体内容，接收 PaddingValues（底部预留了 MiniPlayer 高度，不含 Bar）
 */
@Composable
fun CollapsibleBottomBarScaffold(
    bottomBar: @Composable () -> Unit,
    miniPlayer: @Composable (onClick: () -> Unit) -> Unit,
    modifier: Modifier = Modifier,
    miniPlayerHeight: androidx.compose.ui.unit.Dp = 56.dp,
    bottomBarHeight: androidx.compose.ui.unit.Dp = 80.dp,
    content: @Composable (PaddingValues, CollapsibleBottomBarState) -> Unit,
) {
    val density = LocalDensity.current
    val barHeightPx = with(density) { bottomBarHeight.toPx() }
    val miniHeightPx = with(density) { miniPlayerHeight.toPx() }

    val scope = rememberCoroutineScope()
    val state = rememberCollapsibleBottomBarState(barHeightPx, scope)
    val connection = remember(state) {
        CollapsibleBottomBarNestedScrollConnection(state, scope)
    }

    Layout(
        modifier = modifier.nestedScroll(connection),
        content = {
            // 0: content
            Box(Modifier) {
                // 给 content 的 bottom padding = miniPlayer + (1-progress)*barHeight
                // 折叠时 content 可以延伸到 Bar 原本的位置
                val contentBottom = miniPlayerHeight + bottomBarHeight * (1f - state.progress)
                content(PaddingValues(bottom = contentBottom), state)
            }
            // 1: bottomBar
            Box(
                modifier = Modifier.graphicsLayer {
                    translationY = state.progress * barHeightPx
                    alpha = 1f - state.progress * 0.6f
                },
            ) { bottomBar() }
            // 2: miniPlayer
            Box {
                miniPlayer {
                    // 点击 MiniPlayer：若 Bar 已折叠，先展开；否则走外部逻辑（如打开 NowPlaying）
                    if (state.progress > 0.5f) state.expandNow()
                }
            }
        },
    ) { measurables, constraints ->
        val (contentM, barM, miniM) = measurables
        val width = constraints.maxWidth
        val height = constraints.maxHeight

        val barPlaceable = barM.measure(constraints.copy(minHeight = 0))
        val miniPlaceable = miniM.measure(constraints.copy(minHeight = 0))
        val contentPlaceable = contentM.measure(
            constraints.copy(minHeight = 0, maxHeight = height),
        )

        layout(width, height) {
            contentPlaceable.place(0, 0)
            // Bar 固定在底部；translationY 已经由 graphicsLayer 处理
            barPlaceable.place(0, height - barPlaceable.height)
            // MiniPlayer 紧贴 Bar 顶部；折叠时 Bar 下移，MiniPlayer 跟着下移到屏幕底部
            val miniBottom = height - barPlaceable.height + (state.progress * barHeightPx).toInt()
            miniPlaceable.place(0, miniBottom - miniPlaceable.height)
        }
    }
}
```

