```kotlin
package io.kyonqi.musicplayer.data.dao

import androidx.room.Dao
import androidx.room.Insert
import androidx.room.OnConflictStrategy
import androidx.room.Query
import io.kyonqi.musicplayer.data.entity.TrackEntity
import kotlinx.coroutines.flow.Flow

/**
 * 音轨数据访问对象
 */
@Dao
interface TrackDao {

    // 获取全部音轨，按标题排序
    @Query("SELECT * FROM tracks ORDER BY title ASC")
    fun getAllTracks(): Flow<List<TrackEntity>>

    // 按添加时间降序
    @Query("SELECT * FROM tracks ORDER BY dateAdded DESC")
    fun getAllTracksByDateAdded(): Flow<List<TrackEntity>>

    // 按时长升序
    @Query("SELECT * FROM tracks ORDER BY durationMs ASC")
    fun getAllTracksByDuration(): Flow<List<TrackEntity>>

    // 按专辑名获取音轨
    @Query("SELECT * FROM tracks WHERE album = :albumName ORDER BY discNumber ASC, trackNumber ASC")
    fun getTracksByAlbum(albumName: String): Flow<List<TrackEntity>>

    // 按艺术家获取音轨
    @Query("SELECT * FROM tracks WHERE artist = :artist ORDER BY album ASC, trackNumber ASC")
    fun getTracksByArtist(artist: String): Flow<List<TrackEntity>>

    // 按文件夹路径获取音轨
    @Query("SELECT * FROM tracks WHERE filePath LIKE :folderPath || '%' ORDER BY displayName ASC")
    fun getTracksByFolder(folderPath: String): Flow<List<TrackEntity>>

    // 搜索音轨（标题、艺术家、专辑模糊匹配）
    @Query("""
        SELECT * FROM tracks 
        WHERE title LIKE '%' || :query || '%' 
           OR artist LIKE '%' || :query || '%' 
           OR album LIKE '%' || :query || '%' 
        ORDER BY title ASC
    """)
    fun searchTracks(query: String): Flow<List<TrackEntity>>

    // 获取所有不同的文件夹路径
    @Query("SELECT DISTINCT SUBSTR(filePath, 1, LENGTH(filePath) - LENGTH(displayName)) AS folder FROM tracks ORDER BY folder ASC")
    fun getAllFolders(): Flow<List<String>>

    // 同步获取全部音轨（非 Flow，用于扫描汇总）
    @Query("SELECT * FROM tracks")
    suspend fun getAllTracksOnce(): List<TrackEntity>

    // 获取全部音轨数量
    @Query("SELECT COUNT(*) FROM tracks")
    suspend fun getTrackCount(): Int

    // 批量插入
    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertAll(tracks: List<TrackEntity>)

    // 单条插入
    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insert(track: TrackEntity)

    // 删除全部
    @Query("DELETE FROM tracks")
    suspend fun deleteAll()

    // 按 URI 删除
    @Query("DELETE FROM tracks WHERE uri = :uri")
    suspend fun deleteByUri(uri: String)

    // 获取所有 URI（用于增量扫描比对）
    @Query("SELECT uri FROM tracks")
    suspend fun getAllUris(): List<String>
}
```

