### 1.11 新建 `scanner/MetadataReader.kt`

```kotlin
package io.kyonqi.musicplayer.scanner

import android.content.Context
import android.media.MediaExtractor
import android.media.MediaFormat
import android.media.MediaMetadataRetriever
import android.net.Uri
import dagger.hilt.android.qualifiers.ApplicationContext
import io.kyonqi.musicplayer.data.entity.TrackEntity
import javax.inject.Inject
import javax.inject.Singleton

/**
 * 元数据读取器
 * 使用 MediaMetadataRetriever 和 MediaExtractor 读取音频文件的详细标签信息
 */
@Singleton
class MetadataReader @Inject constructor(
    @ApplicationContext private val context: Context
) {

    /**
     * 读取指定 URI 的详细元数据，返回 TrackEntity
     * 读取失败时使用 fallback 值（文件名等）
     */
    fun readMetadata(
        uri: Uri,
        displayName: String,
        fileSize: Long,
        mimeType: String,
        dateModified: Long,
        filePath: String = "",
    ): TrackEntity {
        val retriever = MediaMetadataRetriever()
        return try {
            retriever.setDataSource(context, uri)

            // 基础标签
            val title = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_TITLE)
                ?: displayName.substringBeforeLast(".")
            val artist = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_ARTIST)
                ?: "未知艺术家"
            val albumArtist = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_ALBUMARTIST)
                ?: ""
            val album = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_ALBUM)
                ?: "未知专辑"
            val genre = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_GENRE)
                ?: ""
            val year = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_YEAR)
                ?.toIntOrNull() ?: 0
            val trackNumber = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_CD_TRACK_NUMBER)
                ?.parseTrackNumber() ?: 0
            val discNumber = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_DISC_NUMBER)
                ?.parseTrackNumber() ?: 0
            val durationMs = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_DURATION)
                ?.toLongOrNull() ?: 0L

            // 采样率和位深通过 MediaExtractor 读取
            val (sampleRate, bitDepth) = extractAudioFormat(uri)

            TrackEntity(
                uri = uri.toString(),
                filePath = filePath,
                displayName = displayName,
                title = title,
                artist = artist,
                albumArtist = albumArtist,
                album = album,
                genre = genre,
                trackNumber = trackNumber,
                discNumber = discNumber,
                year = year,
                durationMs = durationMs,
                size = fileSize,
                mimeType = mimeType,
                sampleRate = sampleRate,
                bitDepth = bitDepth,
                dateModified = dateModified,
                dateAdded = System.currentTimeMillis(),
            )
        } catch (e: Exception) {
            // 读取失败，使用基本信息创建实体
            TrackEntity(
                uri = uri.toString(),
                filePath = filePath,
                displayName = displayName,
                title = displayName.substringBeforeLast("."),
                size = fileSize,
                mimeType = mimeType,
                dateModified = dateModified,
                dateAdded = System.currentTimeMillis(),
            )
        } finally {
            retriever.release()
        }
    }

    /**
     * 通过 MediaExtractor 读取采样率和位深
     */
    private fun extractAudioFormat(uri: Uri): Pair<Int, Int> {
        val extractor = MediaExtractor()
        return try {
            extractor.setDataSource(context, uri, null)
            for (i in 0 until extractor.trackCount) {
                val format = extractor.getTrackFormat(i)
                val mime = format.getString(MediaFormat.KEY_MIME) ?: continue
                if (mime.startsWith("audio/")) {
                    val sampleRate = format.getIntOrDefault(MediaFormat.KEY_SAMPLE_RATE, 0)
                    val bitDepth = format.getIntOrDefault(
                        MediaFormat.KEY_PCM_ENCODING, 0
                    ).toBitDepth()
                    return@try Pair(sampleRate, bitDepth)
                }
            }
            Pair(0, 0)
        } catch (e: Exception) {
            Pair(0, 0)
        } finally {
            extractor.release()
        }
    }
}

// 解析音轨号（可能是 "3/12" 格式）
private fun String.parseTrackNumber(): Int {
    return split("/").firstOrNull()?.trim()?.toIntOrNull() ?: 0
}

// MediaFormat 安全读取整数
private fun MediaFormat.getIntOrDefault(key: String, default: Int): Int {
    return try {
        getInteger(key)
    } catch (e: Exception) {
        default
    }
}

// PCM 编码值转位深
private fun Int.toBitDepth(): Int {
    return when (this) {
        2 -> 16    // AudioFormat.ENCODING_PCM_16BIT
        3 -> 8     // AudioFormat.ENCODING_PCM_8BIT
        4 -> 32    // AudioFormat.ENCODING_PCM_FLOAT
        21 -> 24   // AudioFormat.ENCODING_PCM_24BIT_PACKED
        22 -> 32   // AudioFormat.ENCODING_PCM_32BIT
        else -> 0
    }
}
```

