### 1.12 新建 `scanner/LibraryScanner.kt`

```kotlin
package io.kyonqi.musicplayer.scanner

import android.content.ContentUris
import android.content.Context
import android.net.Uri
import android.provider.MediaStore
import dagger.hilt.android.qualifiers.ApplicationContext
import io.kyonqi.musicplayer.data.dao.AlbumDao
import io.kyonqi.musicplayer.data.dao.ArtistDao
import io.kyonqi.musicplayer.data.dao.TrackDao
import io.kyonqi.musicplayer.data.entity.AlbumEntity
import io.kyonqi.musicplayer.data.entity.ArtistEntity
import io.kyonqi.musicplayer.data.entity.TrackEntity
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.withContext
import javax.inject.Inject
import javax.inject.Singleton

/**
 * 扫描进度状态
 */
data class ScanProgress(
    val isScanning: Boolean = false,
    val current: Int = 0,
    val total: Int = 0,
    val message: String = "",
)

/**
 * 音乐库扫描器
 * 替代原来的 FileScanner，负责完整的扫描 → 元数据读取 → 入库流程
 */
@Singleton
class LibraryScanner @Inject constructor(
    @ApplicationContext private val context: Context,
    private val metadataReader: MetadataReader,
    private val trackDao: TrackDao,
    private val albumDao: AlbumDao,
    private val artistDao: ArtistDao,
) {
    // 扫描进度
    private val _scanProgress = MutableStateFlow(ScanProgress())
    val scanProgress: StateFlow<ScanProgress> = _scanProgress.asStateFlow()

    /**
     * 全量扫描：清库重建
     */
    suspend fun fullScan() = withContext(Dispatchers.IO) {
        _scanProgress.value = ScanProgress(isScanning = true, message = "正在清理旧数据...")

        // 清除旧数据
        trackDao.deleteAll()
        albumDao.deleteAll()
        artistDao.deleteAll()

        // 从 MediaStore 查询所有音频文件
        val rawEntries = queryMediaStore()
        _scanProgress.value = ScanProgress(
            isScanning = true, total = rawEntries.size, message = "正在读取元数据..."
        )

        // 逐个读取元数据并入库（分批插入提高性能）
        val tracks = mutableListOf<TrackEntity>()
        rawEntries.forEachIndexed { index, entry ->
            val track = metadataReader.readMetadata(
                uri = entry.uri,
                displayName = entry.displayName,
                fileSize = entry.size,
                mimeType = entry.mimeType,
                dateModified = entry.dateModified,
                filePath = entry.filePath,
            )
            tracks.add(track)

            _scanProgress.value = _scanProgress.value.copy(
                current = index + 1,
                message = "正在扫描: ${entry.displayName}"
            )

            // 每 50 条批量插入一次
            if (tracks.size >= 50) {
                trackDao.insertAll(tracks)
                tracks.clear()
            }
        }
        // 插入剩余的
        if (tracks.isNotEmpty()) {
            trackDao.insertAll(tracks)
        }

        // 构建专辑和艺术家汇总表
        _scanProgress.value = _scanProgress.value.copy(message = "正在整理音乐库...")
        buildAlbumSummary()
        buildArtistSummary()

        _scanProgress.value = ScanProgress(isScanning = false, message = "扫描完成")
    }

    /**
     * 增量扫描：只更新变化的文件
     */
    suspend fun incrementalScan() = withContext(Dispatchers.IO) {
        _scanProgress.value = ScanProgress(isScanning = true, message = "正在检查变化...")

        val existingUris = trackDao.getAllUris().toSet()
        val rawEntries = queryMediaStore()

        // 找出新增和已删除的
        val currentUris = rawEntries.map { it.uri.toString() }.toSet()
        val newEntries = rawEntries.filter { it.uri.toString() !in existingUris }
        val deletedUris = existingUris - currentUris

        // 删除不存在的
        deletedUris.forEach { trackDao.deleteByUri(it) }

        _scanProgress.value = ScanProgress(
            isScanning = true, total = newEntries.size, message = "正在扫描新文件..."
        )

        // 添加新文件
        val tracks = mutableListOf<TrackEntity>()
        newEntries.forEachIndexed { index, entry ->
            val track = metadataReader.readMetadata(
                uri = entry.uri,
                displayName = entry.displayName,
                fileSize = entry.size,
                mimeType = entry.mimeType,
                dateModified = entry.dateModified,
                filePath = entry.filePath,
            )
            tracks.add(track)
            _scanProgress.value = _scanProgress.value.copy(current = index + 1)

            if (tracks.size >= 50) {
                trackDao.insertAll(tracks)
                tracks.clear()
            }
        }
        if (tracks.isNotEmpty()) {
            trackDao.insertAll(tracks)
        }

        // 重新构建汇总表
        if (newEntries.isNotEmpty() || deletedUris.isNotEmpty()) {
            albumDao.deleteAll()
            artistDao.deleteAll()
            buildAlbumSummary()
            buildArtistSummary()
        }

        _scanProgress.value = ScanProgress(isScanning = false, message = "扫描完成")
    }

    /**
     * 从 MediaStore 查询原始音频条目
     */
    private fun queryMediaStore(): List<RawAudioEntry> {
        val entries = mutableListOf<RawAudioEntry>()

        val projection = arrayOf(
            MediaStore.Audio.Media._ID,
            MediaStore.Audio.Media.DISPLAY_NAME,
            MediaStore.Audio.Media.SIZE,
            MediaStore.Audio.Media.MIME_TYPE,
            MediaStore.Audio.Media.DATE_MODIFIED,
            MediaStore.Audio.Media.DATA,         // 文件路径
            MediaStore.Audio.Media.DURATION,
        )

        val selection = "${MediaStore.Audio.Media.DURATION} > ?"
        val selectionArgs = arrayOf("30000")
        val sortOrder = "${MediaStore.Audio.Media.TITLE} ASC"

        context.contentResolver.query(
            MediaStore.Audio.Media.EXTERNAL_CONTENT_URI,
            projection, selection, selectionArgs, sortOrder
        )?.use { cursor ->
            val idCol = cursor.getColumnIndexOrThrow(MediaStore.Audio.Media._ID)
            val nameCol = cursor.getColumnIndexOrThrow(MediaStore.Audio.Media.DISPLAY_NAME)
            val sizeCol = cursor.getColumnIndexOrThrow(MediaStore.Audio.Media.SIZE)
            val mimeCol = cursor.getColumnIndexOrThrow(MediaStore.Audio.Media.MIME_TYPE)
            val dateCol = cursor.getColumnIndexOrThrow(MediaStore.Audio.Media.DATE_MODIFIED)
            val dataCol = cursor.getColumnIndexOrThrow(MediaStore.Audio.Media.DATA)

            while (cursor.moveToNext()) {
                val id = cursor.getLong(idCol)
                val uri = ContentUris.withAppendedId(
                    MediaStore.Audio.Media.EXTERNAL_CONTENT_URI, id
                )
                entries.add(
                    RawAudioEntry(
                        uri = uri,
                        displayName = cursor.getString(nameCol) ?: "Unknown",
                        size = cursor.getLong(sizeCol),
                        mimeType = cursor.getString(mimeCol) ?: "",
                        dateModified = cursor.getLong(dateCol),
                        filePath = cursor.getString(dataCol) ?: "",
                    )
                )
            }
        }
        return entries
    }

    /**
     * 从 tracks 表构建专辑汇总
     */
    private suspend fun buildAlbumSummary() {
        val allTracks = trackDao.getAllTracksOnce()
        val albumGroups = allTracks.groupBy { Pair(it.album, it.albumArtist.ifEmpty { it.artist }) }
        val albumEntities = albumGroups.map { (key, tracks) ->
            val (albumName, artistName) = key
            val coverUri = tracks.firstOrNull()?.uri ?: ""
            AlbumEntity(
                name = albumName,
                artist = artistName,
                trackCount = tracks.size,
                coverUri = coverUri,
                year = tracks.maxOf { it.year },
            )
        }
        albumDao.insertAll(albumEntities)
    }

    /**
     * 从 tracks 表构建艺术家汇总
     */
    private suspend fun buildArtistSummary() {
        val allTracks = trackDao.getAllTracksOnce()
        val artistGroups = allTracks.groupBy { it.artist }
        val artistEntities = artistGroups.map { (name, tracks) ->
            val albumCount = tracks.map { it.album }.distinct().size
            ArtistEntity(
                name = name,
                albumCount = albumCount,
                trackCount = tracks.size,
            )
        }
        artistDao.insertAll(artistEntities)
    }
}

/**
 * MediaStore 查询的原始条目（只含文件层面信息，不含标签）
 */
private data class RawAudioEntry(
    val uri: Uri,
    val displayName: String,
    val size: Long,
    val mimeType: String,
    val dateModified: Long,
    val filePath: String,
)
