/**
 * 专辑封面组件
 * 使用 Coil AsyncImage 加载封面
 * 加载失败时显示默认音乐图标
 */
@Composable
fun AlbumArt(
    uri: Uri?,
    modifier: Modifier = Modifier,
    size: Dp = 48.dp,
    contentDescription: String? = "专辑封面",
) {
    if (uri == null) {
        AlbumArtPlaceholder(modifier = modifier.size(size))
        return
    }

    val context = LocalContext.current
    val model = ImageRequest.Builder(context)
        .data(uri)
        .crossfade(true)
        .build()

    AsyncImage(
        model = model,
        contentDescription = contentDescription,
        modifier = modifier.size(size),
        contentScale = ContentScale.Crop,
        error = {
            AlbumArtPlaceholder(modifier = Modifier.fillMaxSize())
        },
    )
}

/**
 * 默认封面占位组件
 */
@Composable
private fun AlbumArtPlaceholder(modifier: Modifier = Modifier) {
    Box(
        modifier = modifier,
        contentAlignment = Alignment.Center
