/**
 * 音乐库主界面 ViewModel
 * 负责管理 Tab 状态和触发初始扫描
 */
@HiltViewModel
class LibraryViewModel @Inject constructor(
    private val libraryScanner: LibraryScanner,
    private val trackDao: TrackDao,
) : ViewModel() {

    // 当前选中的 Tab 索引
    private val _selectedTab = MutableStateFlow(0)
    val selectedTab = _selectedTab.asStateFlow()

    // 扫描进度
    val scanProgress = libraryScanner.scanProgress

    // 数据库中的音轨数量
    private val _trackCount = MutableStateFlow(0)
    val trackCount = _trackCount.asStateFlow()

    // Tab 标题列表
    val tabs = listOf("歌曲", "专辑", "艺术家", "文件夹")

    fun selectTab(index: Int) {
        _selectedTab.value = index
    }

    // 首次加载时检查数据库，如果空则全量扫描
    fun initLibrary() {
        viewModelScope.launch {
            val count = trackDao.getTrackCount()
            _trackCount.value = count
            if (count == 0) {
                libraryScanner.fullScan()
                _trackCount.value = trackDao.getTrackCount()
            }
        }
    }

    // 手动刷新
    fun refreshLibrary() {
        viewModelScope.launch {
            libraryScanner.incrementalScan()
            _trackCount.value = trackDao.getTrackCount()
        }
    }
}

/**
 * 音乐库主屏幕
 * 包含权限检查、Tab 导航、扫描进度显示
 */
@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun LibraryScreen(
    onNavigateToAlbumDetail: (Long) -> Unit,
    onNavigateToArtistDetail: (Long) -> Unit,
    onNavigateToNowPlaying: () -> Unit,
    onNavigateToSearch: () -> Unit,
    onNavigateToQueue: () -> Unit,
    viewModel: LibraryViewModel = hiltViewModel(),
) {
    val selectedTab by viewModel.selectedTab.collectAsStateWithLifecycle()
    val scanProgress by viewModel.scanProgress.collectAsStateWithLifecycle()

    // 权限处理
    val permission = if (Build.VERSION.SDK_INT >= 33) {
        Manifest.permission.READ_MEDIA_AUDIO
    } else {
        Manifest.permission.READ_EXTERNAL_STORAGE
    }
    PermissionHandler(
        permission = permission,
        onGranted = { viewModel.initLibrary() }
    )

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("音乐库") },
                actions = {
                    // 搜索按钮
                    IconButton(onClick = onNavigateToSearch) {
                        Icon(Icons.Default.Search, "搜索")
                    }
                    // 刷新按钮
                    IconButton(onClick = { viewModel.refreshLibrary() }) {
                        Icon(Icons.Default.Refresh, "刷新")
                    }
                }
            )
        }
    ) { padding ->
        Column(modifier = Modifier.fillMaxSize().padding(padding)) {
            // 扫描进度条
            if (scanProgress.isScanning) {
                LinearProgressIndicator(
                    progress = {
                        if (scanProgress.total > 0)
                            scanProgress.current.toFloat() / scanProgress.total
                        else 0f
                    },
                    modifier = Modifier.fillMaxWidth()
                )
                Text(
                    text = scanProgress.message,
                    style = MaterialTheme.typography.labelSmall,
                    modifier = Modifier.padding(horizontal = 16.dp, vertical = 4.dp)
                )
            }

            // Tab 栏
            TabRow(selectedTabIndex = selectedTab) {
                viewModel.tabs.forEachIndexed { index, title ->
                    Tab(
                        selected = selectedTab == index,
                        onClick = { viewModel.selectTab(index) },
                        text = { Text(title) }
                    )
                }
            }

            // Tab 内容
            when (selectedTab) {
                0 -> SongListScreen(onNavigateToNowPlaying = onNavigateToNowPlaying)
                1 -> AlbumListScreen(onAlbumClick = onNavigateToAlbumDetail)
                2 -> ArtistListScreen(onArtistClick = onNavigateToArtistDetail)
                3 -> FolderBrowserScreen()
            }
        }
    }
}
