@Composable
private fun SortBar(
    currentOrder: SongSortOrder,
    onOrderChange: (SongSortOrder) -> Unit,
) {
    Row(
        modifier = Modifier.fillMaxWidth().padding(horizontal = 16.dp, vertical = 8.dp),
        horizontalArrangement = Arrangement.spacedBy(8.dp)
    ) {
        SongSortOrder.entries.forEach { order ->
            FilterChip(
                selected = currentOrder == order,
                onClick = { onOrderChange(order) },
                label = {
                    Text(
                        when (order) {
                            SongSortOrder.TITLE -> "名称"
                            SongSortOrder.DATE_ADDED -> "添加时间"
                            SongSortOrder.DURATION -> "时长"
                        }
                    )
                }
            )
        }
    }
}

private fun formatDuration(ms: Long): String {
    val totalSeconds = ms / 1000
    return "%d:%02d".format(totalSeconds / 60, totalSeconds % 60)
