    private val trackDao: TrackDao,
    private val player: PlayerController,
) : ViewModel() {

    private val albumId: Long = savedStateHandle.get<Long>("albumId") ?: 0L

    private val _album = MutableStateFlow<AlbumEntity?>(null)
    val album = _album.asStateFlow()

    private val _tracks = MutableStateFlow<List<TrackEntity>>(emptyList())
    val tracks = _tracks.asStateFlow()

    init {
        viewModelScope.launch {
            val albumEntity = albumDao.getAlbumById(albumId)
            _album.value = albumEntity
            albumEntity?.let { a ->
                trackDao.getTracksByAlbum(a.name).collect { trackList ->
                    _tracks.value = trackList
                }
            }
        }
    }

    // 播放全部
    fun playAll() {
        val trackList = _tracks.value
        if (trackList.isNotEmpty()) {
            player.setQueue(trackList.toAudioFiles(), 0)
        }
    }

    // 播放指定曲目
    fun playAt(index: Int) {
        val trackList = _tracks.value
        if (index in trackList.indices) {
            player.setQueue(trackList.toAudioFiles(), index)
        }
    }
}

