@HiltViewModel
class FolderBrowserViewModel @Inject constructor(
    private val trackDao: TrackDao,
    private val player: PlayerController,
) : ViewModel() {

    // 所有文件夹路径
    val folders: StateFlow<List<String>> = trackDao.getAllFolders()
        .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), emptyList())

    // 当前展开的文件夹及其歌曲
    private val _expandedFolder = MutableStateFlow<String?>(null)
    val expandedFolder = _expandedFolder.asStateFlow()

    private val _folderTracks = MutableStateFlow<List<TrackEntity>>(emptyList())
    val folderTracks = _folderTracks.asStateFlow()

    fun toggleFolder(folderPath: String) {
        if (_expandedFolder.value == folderPath) {
            _expandedFolder.value = null
            _folderTracks.value = emptyList()
        } else {
            _expandedFolder.value = folderPath
            viewModelScope.launch {
                trackDao.getTracksByFolder(folderPath).collect {
                    _folderTracks.value = it
                }
            }
        }
    }

    fun playTrack(index: Int) {
        val trackList = _folderTracks.value
        if (index in trackList.indices) {
            player.setQueue(trackList.toAudioFiles(), index)
        }
    }
}

