### 3.9 新建 `data/dao/PlaylistDao.kt`

```kotlin
package io.kyonqi.musicplayer.data.dao

import androidx.room.Dao
import androidx.room.Insert
import androidx.room.OnConflictStrategy
import androidx.room.Query
import androidx.room.Transaction
import io.kyonqi.musicplayer.data.entity.PlaylistEntity
import io.kyonqi.musicplayer.data.entity.PlaylistTrackCrossRef
import io.kyonqi.musicplayer.data.entity.TrackEntity
import kotlinx.coroutines.flow.Flow

/**
 * 播放列表数据访问对象
 */
@Dao
interface PlaylistDao {

    // 获取全部播放列表
    @Query("SELECT * FROM playlists ORDER BY updatedAt DESC")
    fun getAllPlaylists(): Flow<List<PlaylistEntity>>

    // 获取播放列表中的歌曲
    @Transaction
    @Query("""
        SELECT t.* FROM tracks t 
        INNER JOIN playlist_track_cross_ref ref ON t.id = ref.trackId 
        WHERE ref.playlistId = :playlistId 
        ORDER BY ref.sortOrder ASC
    """)
    fun getTracksForPlaylist(playlistId: Long): Flow<List<TrackEntity>>

    // 创建播放列表
    @Insert
    suspend fun createPlaylist(playlist: PlaylistEntity): Long

    // 添加歌曲到播放列表
    @Insert(onConflict = OnConflictStrategy.IGNORE)
    suspend fun addTrackToPlaylist(crossRef: PlaylistTrackCrossRef)

    // 从播放列表移除歌曲
    @Query("DELETE FROM playlist_track_cross_ref WHERE playlistId = :playlistId AND trackId = :trackId")
    suspend fun removeTrackFromPlaylist(playlistId: Long, trackId: Long)

    // 删除播放列表
    @Query("DELETE FROM playlists WHERE playlistId = :playlistId")
    suspend fun deletePlaylist(playlistId: Long)

    // 更新播放列表的 updatedAt
    @Query("UPDATE playlists SET updatedAt = :timestamp WHERE playlistId = :playlistId")
    suspend fun updateTimestamp(playlistId: Long, timestamp: Long = System.currentTimeMillis())
}
