    private val _state = MutableStateFlow(SearchState())
    val state: StateFlow<SearchState> = _state.asStateFlow()

    // 搜索查询（带防抖）
    private val _queryFlow = MutableStateFlow("")

    init {
        viewModelScope.launch {
            _queryFlow
                .debounce(300)
                .distinctUntilChanged()
                .collectLatest { query ->
                    if (query.isBlank()) {
                        _state.value = SearchState()
                        return@collectLatest
                    }
                    // 并行搜索歌曲、专辑、艺术家
                    coroutineScope {
                        val tracksDeferred = async {
                            trackDao.searchTracks(query).first()
                        }
                        val albumsDeferred = async {
                            albumDao.searchAlbums(query).first()
                        }
                        val artistsDeferred = async {
                            artistDao.searchArtists(query).first()
                        }
                        _state.value = SearchState(
                            query = query,
                            tracks = tracksDeferred.await(),
                            albums = albumsDeferred.await(),
                            artists = artistsDeferred.await(),
                        )
                    }
                }
        }
    }

    fun updateQuery(query: String) {
        _queryFlow.value = query
        _state.update { it.copy(query = query) }
    }

    fun playTrack(tracks: List<TrackEntity>, index: Int) {
        if (index in tracks.indices) {
            player.setQueue(tracks.toAudioFiles(), index)
        }
    }
}

/**
 * 搜索页面
 */
