## 3. ExoPlayer 实现

### player/ExoPlayerController.kt

```kotlin
package com.example.musicplayer.player

import android.content.Context
import androidx.media3.common.MediaItem
import androidx.media3.common.Player
import androidx.media3.exoplayer.ExoPlayer
import com.example.musicplayer.model.AudioFile
import dagger.hilt.android.qualifiers.ApplicationContext
import kotlinx.coroutines.*
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
import javax.inject.Inject
import javax.inject.Singleton

@Singleton
class ExoPlayerController @Inject constructor(
    @ApplicationContext private val context: Context
) : PlayerController {

    private val _state = MutableStateFlow(PlaybackState())
    override val playbackState: StateFlow<PlaybackState> = _state.asStateFlow()

    private val scope = CoroutineScope(Dispatchers.Main + SupervisorJob())
    private var positionJob: Job? = null

    private val exoPlayer: ExoPlayer by lazy {
        ExoPlayer.Builder(context).build().also { player ->
            player.addListener(object : Player.Listener {

                override fun onIsPlayingChanged(isPlaying: Boolean) {
                    _state.update { it.copy(isPlaying = isPlaying) }
                    if (isPlaying) startPositionTracking() else stopPositionTracking()
                }

                override fun onMediaItemTransition(mediaItem: MediaItem?, reason: Int) {
                    val index = player.currentMediaItemIndex
                    val queue = _state.value.queue
                    _state.update {
                        it.copy(
                            currentTrack = queue.getOrNull(index),
                            currentIndex = index,
                            durationMs = player.duration.coerceAtLeast(0)
                        )
                    }
                }

                override fun onPlaybackStateChanged(state: Int) {
                    if (state == Player.STATE_READY) {
                        _state.update { it.copy(durationMs = player.duration.coerceAtLeast(0)) }
                    }
                }
            })
        }
    }

    override fun play(track: AudioFile) {
        setQueue(listOf(track), 0)
    }

    override fun setQueue(tracks: List<AudioFile>, startIndex: Int) {
        _state.update { it.copy(queue = tracks, currentIndex = startIndex) }
        val mediaItems = tracks.map { MediaItem.fromUri(it.uri) }
        exoPlayer.setMediaItems(mediaItems, startIndex, 0L)
        exoPlayer.prepare()
        exoPlayer.play()
    }

    override fun playAt(index: Int) {
        exoPlayer.seekTo(index, 0L)
        exoPlayer.play()
    }

    override fun togglePlayPause() {
        if (exoPlayer.isPlaying) exoPlayer.pause() else exoPlayer.play()
    }

    override fun seekTo(positionMs: Long) {
        exoPlayer.seekTo(positionMs)
        _state.update { it.copy(positionMs = positionMs) }
    }

    override fun next() {
        if (exoPlayer.hasNextMediaItem()) exoPlayer.seekToNextMediaItem()
    }

    override fun previous() {
        // 播放超过 3 秒则回到开头，否则上一首
        if (exoPlayer.currentPosition > 3000) {
            exoPlayer.seekTo(0)
        } else if (exoPlayer.hasPreviousMediaItem()) {
            exoPlayer.seekToPreviousMediaItem()
        }
    }

    override fun release() {
        stopPositionTracking()
        scope.cancel()
        exoPlayer.release()
    }

    // ---------- 内部方法 ----------

    /** 每 200ms 更新一次播放进度 */
    private fun startPositionTracking() {
        stopPositionTracking()
        positionJob = scope.launch {
            while (isActive) {
                _state.update { it.copy(positionMs = exoPlayer.currentPosition.coerceAtLeast(0)) }
                delay(200)
            }
        }
    }

    private fun stopPositionTracking() {
        positionJob?.cancel()
        positionJob = null
    }

    /** 暴露内部 ExoPlayer 实例，仅供 PlaybackService 使用 */
    fun getExoPlayer(): ExoPlayer = exoPlayer
}
```

