import androidx.compose.ui.text.style.TextOverflow
import androidx.compose.ui.unit.dp
import androidx.hilt.navigation.compose.hiltViewModel
import androidx.lifecycle.ViewModel
import androidx.lifecycle.compose.collectAsStateWithLifecycle
import androidx.lifecycle.viewModelScope
import com.example.musicplayer.model.AudioFile
import com.example.musicplayer.player.PlayerController
import com.example.musicplayer.scanner.FileScanner
import com.example.musicplayer.ui.component.PermissionHandler
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch
import javax.inject.Inject

// ---------- ViewModel ----------

@HiltViewModel
class FileBrowserViewModel @Inject constructor(
    private val scanner: FileScanner,
    private val player: PlayerController
) : ViewModel() {

    private val _tracks = MutableStateFlow<List<AudioFile>>(emptyList())
    val tracks = _tracks.asStateFlow()

    private val _isLoading = MutableStateFlow(false)
    val isLoading = _isLoading.asStateFlow()

    fun loadTracks() {
        viewModelScope.launch {
            _isLoading.value = true
            _tracks.value = scanner.scanAllAudio()
            _isLoading.value = false
        }
    }

    fun onTrackClick(index: Int) {
        val trackList = _tracks.value
        if (index in trackList.indices) {
            player.setQueue(trackList, index)
        }
    }
}

// ---------- Screen ----------

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun FileBrowserScreen(
    onTrackClick: () -> Unit = {},
    onOpenNowPlaying: () -> Unit = {},
    viewModel: FileBrowserViewModel = hiltViewModel()
) {
    val tracks by viewModel.tracks.collectAsStateWithLifecycle()
    val isLoading by viewModel.isLoading.collectAsStateWithLifecycle()

    // 处理存储权限
    val permission = if (Build.VERSION.SDK_INT >= 33) {
        Manifest.permission.READ_MEDIA_AUDIO
    } else {
        Manifest.permission.READ_EXTERNAL_STORAGE
    }

    PermissionHandler(
        permission = permission,
        onGranted = { viewModel.loadTracks() }
    )

    Scaffold(
        topBar = {
            TopAppBar(title = { Text("音乐库") })
        }
    ) { padding ->
        Box(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
        ) {
            when {
                isLoading -> {
                    CircularProgressIndicator(
                        modifier = Modifier.align(Alignment.Center)
                    )
                }
                tracks.isEmpty() -> {
                    Text(
                        text = "未找到音频文件",
                        modifier = Modifier.align(Alignment.Center),
                        style = MaterialTheme.typography.bodyLarge
                    )
                }
                else -> {
                    LazyColumn(modifier = Modifier.fillMaxSize()) {
                        itemsIndexed(tracks) { index, track ->
                            TrackItem(
                                track = track,
                                onClick = { viewModel.onTrackClick(index) }
                            )
                        }
                    }
                }
            }
        }
    }
}

@Composable
private fun TrackItem(track: AudioFile, onClick: () -> Unit) {
    ListItem(
        headlineContent = {
            Text(track.title, maxLines = 1, overflow = TextOverflow.Ellipsis)
        },
        supportingContent = {
            Text(
                "${track.artist} · ${formatDuration(track.durationMs)}",
                maxLines = 1,
                overflow = TextOverflow.Ellipsis
            )
        },
        leadingContent = {
            Icon(Icons.Default.MusicNote, contentDescription = null)
        },
        modifier = Modifier.clickable(onClick = onClick)
    )
}

private fun formatDuration(ms: Long): String {
    val totalSeconds = ms / 1000
    val minutes = totalSeconds / 60
    val seconds = totalSeconds % 60
    return "%d:%02d".format(minutes, seconds)
}
