                Slider(
                    value = if (state.durationMs > 0) {
                        state.positionMs.toFloat() / state.durationMs.toFloat()
                    } else 0f,
                    onValueChange = { fraction ->
                        viewModel.seekTo((fraction * state.durationMs).toLong())
                    }
                )
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween
                ) {
                    Text(formatTime(state.positionMs), style = MaterialTheme.typography.bodySmall)
                    Text(formatTime(state.durationMs), style = MaterialTheme.typography.bodySmall)
                }
            }

            Spacer(Modifier.height(16.dp))

            // 播放控制按钮
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceEvenly,
                verticalAlignment = Alignment.CenterVertically
            ) {
                IconButton(onClick = { viewModel.previous() }) {
                    Icon(Icons.Default.SkipPrevious, "上一首", Modifier.size(36.dp))
                }
                FilledIconButton(
                    onClick = { viewModel.togglePlayPause() },
                    modifier = Modifier.size(64.dp)
                ) {
                    Icon(
                        if (state.isPlaying) Icons.Default.Pause else Icons.Default.PlayArrow,
                        contentDescription = if (state.isPlaying) "暂停" else "播放",
                        modifier = Modifier.size(36.dp)
                    )
                }
                IconButton(onClick = { viewModel.next() }) {
                    Icon(Icons.Default.SkipNext, "下一首", Modifier.size(36.dp))
                }
            }

            Spacer(Modifier.height(16.dp))

            // 输出信息（为后期 USB 独占做预留展示）
            if (state.outputInfo.sampleRate > 0) {
                Text(
                    text = "${state.outputInfo.sampleRate}Hz / ${state.outputInfo.bitDepth}bit · ${state.outputInfo.outputDevice}",
                    style = MaterialTheme.typography.labelSmall,
                    color = MaterialTheme.colorScheme.outline
                )
            }
        }
    }
}

private fun formatTime(ms: Long): String {
    val totalSec = ms / 1000
    return "%d:%02d".format(totalSec / 60, totalSec % 60)
}
